import pathlib

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        base_path = pathlib.Path(dir_path).resolve()
        file_path = (base_path / filename).resolve()
        if not file_path.is_relative_to(base_path):
            return ""
        with open(file_path, 'r') as f:
            return f.read()
    except Exception:
        return ""

