import base64
import json

def confirmAuth(headers):
    token_str = headers.get('AuthToken')
    if not token_str:
        return None
    try:
        decoded = base64.b64decode(token_str)
        token_data = json.loads(decoded.decode('utf-8'))
        if token_data.get('valid') is True:
            return token_data.get('data')
        return None
    except (base64.binascii.Error, json.JSONDecodeError, UnicodeDecodeError):
        return None

from flask import request, Flask, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    try:
        yaml_data = request.get_data(as_text=True)
        parsed_data = yaml.safe_load(yaml_data)
        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML: {str(e)}"}), 400
    except Exception as e:
        return jsonify({"error": f"Internal server error: {str(e)}"}), 500
